optimized_federated_query:
# Smart Federated Query with Class Constraints
# Note: Multiple class interpretations exist but all route to same endpoints
# A single query retrieves all data regardless of class ambiguity

SELECT ?cas ?drug ?keggDrug ?mass ?transform
WHERE {

  SERVICE <http://localhost:8892/sparql/> {
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/biotransformation> ?transform . # ?drug:drugs, ?transform:Literal
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/affectedOrganism> "Humans and other mammals" . # ?drug:drugs
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/casRegistryNumber> ?cas .
  }

  SERVICE <http://localhost:8895/sparql/> {
    ?keggDrug <http://bio2rdf.org/ns/bio2rdf#mass> ?mass . # ?keggDrug:Drug, ?mass:Literal
    ?keggDrug <http://bio2rdf.org/ns/bio2rdf#xRef> ?cas .
  }
}
LIMIT 1000
